    let mut group = c.benchmark_group("grapheme_iteration");

    // ASCII only
    let ascii = "The quick brown fox jumps over the lazy dog. ".repeat(100);
    group.bench_function("ascii_5000_chars", |b| {
        b.iter(|| {
            for grapheme in ascii.graphemes(true) {
