fn bench_editor_frame(c: &mut Criterion) {
    // Simulate rendering a code editor frame
    // - Draw line numbers
    // - Draw code lines with basic highlighting
    // - Draw status bar
    // - Calculate diff and present

    let code = include_str!("../src/lib.rs");  // Real code
    let lines: Vec<&str> = code.lines().collect();

    let mut group = c.benchmark_group("editor_frame");

    group.bench_function("render_80x24_50_lines", |b| {
        let mut front = OptimizedBuffer::new(80, 24);
        let mut back = OptimizedBuffer::new(80, 24);
        let mut scroll = 0;

        b.iter(|| {
            back.clear(Rgba::from_rgb_u8(30, 30, 40));

            // Line numbers
            for y in 0..22 {
                let line_num = scroll + y;
                if line_num < lines.len() {
                    let num_str = format!("{:4} ", line_num + 1);
                    back.draw_text(0, y as u32, &num_str, Style::dim());
                }
            }

            // Code lines
            for y in 0..22 {
                let line_num = scroll + y;
                if line_num < lines.len() {
                    let line = lines[line_num];
                    let display: String = line.chars().take(74).collect();
                    back.draw_text(5, y as u32, &display, Style::default());
                }
            }

            // Status bar
            back.fill_rect(0, 23, 80, 1, Rgba::from_rgb_u8(60, 60, 80));
            back.draw_text(1, 23, " src/lib.rs | Ln 1, Col 1 ", Style::default());

            // Diff
            let diff = BufferDiff::compute(&front, &back);
            std::mem::swap(&mut front, &mut back);
            scroll = (scroll + 1) % lines.len().saturating_sub(22);

            black_box(diff);
        })
    });

    group.finish();
}
```

