fn bench_animation_frame(c: &mut Criterion) {
    // Simulate an animation with multiple moving elements
    // - Background
    // - 50 animated particles
    // - Progress bar
    // - FPS counter

    struct Particle { x: f32, y: f32, vx: f32, vy: f32, color: Rgba }

    let mut particles: Vec<Particle> = (0..50).map(|i| {
        Particle {
            x: (i * 17 % 80) as f32,
            y: (i * 13 % 24) as f32,
            vx: ((i % 5) as f32 - 2.0) * 0.5,
            vy: ((i % 7) as f32 - 3.0) * 0.3,
            color: Rgba::from_hsv((i * 15 % 360) as f32, 0.8, 1.0),
        }
    }).collect();

    let mut group = c.benchmark_group("animation_frame");

    group.bench_function("render_50_particles", |b| {
        let mut buffer = OptimizedBuffer::new(80, 24);
        let mut frame = 0;

        b.iter(|| {
            buffer.clear(Rgba::from_rgb_u8(20, 20, 30));

            // Update and draw particles
            for p in &mut particles {
                p.x = (p.x + p.vx).rem_euclid(80.0);
                p.y = (p.y + p.vy).rem_euclid(24.0);
                buffer.set_blended(
                    p.x as u32,
                    p.y as u32,
                    Cell::new('●', Style::fg(p.color)),
                );
            }

            // Progress bar
            let progress = (frame % 100) as f32 / 100.0;
            let filled = (progress * 60.0) as u32;
            buffer.draw_text(10, 22, "[", Style::default());
            for i in 0..60 {
                let ch = if i < filled { '█' } else { '░' };
                buffer.set(11 + i, 22, Cell::new(ch, Style::default()));
            }
            buffer.draw_text(71, 22, "]", Style::default());

            frame += 1;
            black_box(&buffer);
        })
    });

    group.finish();
}
