use std::process::Command;
use std::time::Duration;
use tracing::{info, warn, error, debug};

fn init_logging() {
    let _ = tracing_subscriber::fmt()
        .with_max_level(tracing::Level::DEBUG)
        .try_init();
}

#[test]
fn benchmarks_compile() {
    init_logging();
    info\!("Validating benchmark compilation");

    let output = Command::new("cargo")
        .args(["build", "--benches"])
        .output()
        .expect("Failed to run cargo");

    if \!output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        error\!(stderr = stderr.as_ref(), "Benchmark compilation failed");
        panic\!("Benchmarks failed to compile");
    }

    info\!("All benchmarks compile successfully");
}

#[test]
fn benchmark_quick_run() {
    init_logging();
    info\!("Running benchmarks in quick mode");

    // Run each benchmark for minimal iterations
    let output = Command::new("cargo")
        .args([
            "bench", 
            "--", 
            "--test",  // Run each benchmark once
            "--warm-up-time", "1",
            "--measurement-time", "1",
        ])
        .timeout(Duration::from_secs(60))
        .output()
        .expect("Failed to run benchmarks");

    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);

    debug\!(stdout = stdout.as_ref(), "Benchmark stdout");
    debug\!(stderr = stderr.as_ref(), "Benchmark stderr");

    // Check for panics or errors
    assert\!(
        \!stderr.contains("panicked") && \!stderr.contains("error[E"),
        "Benchmarks should not panic or error"
    );

    info\!("Benchmark quick run completed successfully");
}
